1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	const COMPONENT_BASE = 25;
5	const FIRST_INS_SURCHARGE = 0.1;
6	const CURSE_SURCHARGE = 0.5;
7	const HIGH_ENCH_SURCHARGE = 0.3;
8	const HIGH_ENCH_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	const HIGH_ENCH_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCH_CLAIM_FACTOR = 0.5;
15	const INSURANCE_VALUE_MULTIPLIER = 10;
16	
17	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	export type Item = {
29	  type: string;
30	  enchantment?: number;
31	  cursed?: boolean;
32	  material?: string;
33	};
34	
35	export type Customer = {
36	  yearsWithMHPCO?: number;
37	};
38	
39	export type QuoteInput = {
40	  customer?: Customer;
41	  items: Item[];
42	  isFollowUp?: boolean;
43	};
44	
45	export type QuoteResult = {
46	  premium: number;
47	};
48	
49	export type DamageEntry = {
50	  itemType: string;
51	  amount: number;
52	};
53	
54	export type Policy = {
55	  items: Item[];
56	  remainingCap: number;
57	};
58	
59	export type Incident = {
60	  cause?: string;
61	  damages: DamageEntry[];
62	};
63	
64	export type ClaimInput = {
65	  policy: Policy;
66	  incident: Incident;
67	};
68	
69	export type ClaimResult = {
70	  payout: number;
71	  remainingCap: number;
72	};
73	
74	export const isKnownItemType = (type: string): boolean =>
75	  type in BASE_PREMIUM_BY_ITEM_TYPE;
76	
77	export const insuranceValueFor = (item: Item): number =>
78	  (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0) * INSURANCE_VALUE_MULTIPLIER;
79	
80	const baseForItem = (item: Item): number =>
81	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
82	
83	const isComponent = (item: Item): boolean =>
84	  COMPONENT_TYPES.has(item.type);
85	
86	const itemModifierSum = (item: Item): number => {
87	  let mod = FIRST_INS_SURCHARGE;
88	  if (item.cursed) mod += CURSE_SURCHARGE;
89	  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
90	  return mod;
91	};
92	
93	const itemCharge = (item: Item): number =>
94	  baseForItem(item) * (1 + itemModifierSum(item));
95	
96	const countByType = (items: Item[]): Record<string, number> => {
97	  const counts: Record<string, number> = {};
98	  for (const item of items) {
99	    counts[item.type] = (counts[item.type] ?? 0) + 1;
100	  }
101	  return counts;
102	};
103	
104	const componentsCharge = (items: Item[]): number => {
105	  const componentItems = items.filter(isComponent);
106	  const counts = countByType(componentItems);
107	  let total = 0;
108	  for (const type in counts) {
109	    const count = counts[type];
110	    if (count === BLOCK_SIZE) {
111	      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
112	    } else {
113	      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
114	    }
115	  }
116	  return total;
117	};
118	
119	const componentsBase = (items: Item[]): number => {
120	  const componentItems = items.filter(isComponent);
121	  const counts = countByType(componentItems);
122	  let total = 0;
123	  for (const type in counts) {
124	    const count = counts[type];
125	    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
126	  }
127	  return total;
128	};
129	
130	const nonComponentsCharge = (items: Item[]): number =>
131	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);
132	
133	const nonComponentsBase = (items: Item[]): number =>
134	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);
135	
136	export function quote(input: QuoteInput): QuoteResult {
137	  const items = input.items;
138	  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
139	  const policyBase = nonComponentsBase(items) + componentsBase(items);
140	  const years = input.customer?.yearsWithMHPCO ?? 0;
141	  let policyModifiers = 0;
142	  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
143	  if (input.isFollowUp) policyModifiers -= FOLLOW_UP_DISCOUNT;
144	  const policyAdjustment = policyBase * policyModifiers;
145	  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
146	  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
147	  return { premium };
148	}
149	
150	export function claim(input: ClaimInput): ClaimResult {
151	  let payout = 0;
152	  for (const damageEntry of input.incident.damages) {
153	    const item = input.policy.items.find((i) => i.type === damageEntry.itemType);
154	    let amount = damageEntry.amount;
155	    if (item && (item.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD) {
156	      amount = amount * HIGH_ENCH_CLAIM_FACTOR;
157	    }
158	    payout += amount - DEDUCTIBLE;
159	  }
160	  payout = Math.min(payout, input.policy.remainingCap);
161	  const remainingCap = input.policy.remainingCap - payout;
162	  return { payout, remainingCap };
163	}
