1	import {
2	  quote,
3	  claim,
4	  insuranceValueFor,
5	  isKnownItemType,
6	  type Customer,
7	  type Item,
8	  type Policy,
9	  type Incident,
10	} from "./claim-office.js";
11	
12	const CAP_MULTIPLIER = 2;
13	
14	type QuoteStep = {
15	  op: "quote";
16	  items: Item[];
17	};
18	
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: Incident;
23	};
24	
25	type Step = QuoteStep | ClaimStep;
26	
27	type Scenario = {
28	  customer: Customer;
29	  steps: Step[];
30	};
31	
32	const readStdin = async (): Promise<string> => {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	};
39	
40	const policyCapFor = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + CAP_MULTIPLIER * insuranceValueFor(item), 0);
42	
43	const validateQuoteItems = (items: Item[]): void => {
44	  const unknown = items.find((item) => !isKnownItemType(item.type));
45	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
46	};
47	
48	const validateClaimDamages = (policy: Policy, damages: Incident["damages"]): void => {
49	  const negative = damages.find((damage) => damage.amount < 0);
50	  if (negative) throw new Error(`Damage amount cannot be negative: ${negative.amount}`);
51	  const uncovered = damages.find(
52	    (damage) => !policy.items.some((item) => item.type === damage.itemType),
53	  );
54	  if (uncovered) throw new Error(`Damage references item not in policy: ${uncovered.itemType}`);
55	};
56	
57	const handleQuote = (
58	  customer: Customer,
59	  step: QuoteStep,
60	  policies: Policy[],
61	): unknown => {
62	  validateQuoteItems(step.items);
63	  const result = quote({ customer, items: step.items });
64	  policies.push({ items: step.items, remainingCap: policyCapFor(step.items) });
65	  return result;
66	};
67	
68	const handleClaim = (step: ClaimStep, policies: Policy[]): unknown => {
69	  const policy = policies[step.policy];
70	  validateClaimDamages(policy, step.incident.damages);
71	  const result = claim({ policy, incident: step.incident });
72	  policy.remainingCap = result.remainingCap;
73	  return result;
74	};
75	
76	const runStep = (
77	  customer: Customer,
78	  step: Step,
79	  policies: Policy[],
80	): unknown =>
81	  step.op === "quote"
82	    ? handleQuote(customer, step, policies)
83	    : handleClaim(step, policies);
84	
85	const runScenario = (scenario: Scenario): unknown[] => {
86	  const policies: Policy[] = [];
87	  return scenario.steps.map((step) => runStep(scenario.customer, step, policies));
88	};
89	
90	const main = async () => {
91	  const input = await readStdin();
92	  const scenario: Scenario = JSON.parse(input);
93	  const results = runScenario(scenario);
94	  process.stdout.write(JSON.stringify({ results }));
95	};
96	
97	main().catch((err) => {
98	  process.stderr.write(String(err));
99	  process.exit(1);
100	});
